#include <stdio.h>
#include <stdlib.h>

#define MAX_N 1000
#define MAX_M 10000

int find(int *parent, int x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}

int unionSet(int *parent, int x, int y) {
    int px = find(parent, x);
    int py = find(parent, y);
    if (px != py) {
        parent[px] = py;
        return 1;
    }
    return 0;
}

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return x[2] - y[2];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        char kinds[N + 1];
        scanf("%s", kinds);
        int edges[M][3];
        for (int i = 0; i < M; i++) {
            scanf("%d %d %d", &edges[i][0], &edges[i][1], &edges[i][2]);
            edges[i][0]--;
            edges[i][1]--;
        }
        qsort(edges, M, sizeof(edges[0]), compare);
        int parent[N];
        for (int i = 0; i < N; i++) {
            parent[i] = i;
        }
        long long res = 0;
        int firstR = -1;
        for (int i = 0; i < N; i++) {
            if (kinds[i] == 'R') {
                firstR = i;
                break;
            }
        }
        for (int i = firstR + 1; i < N; i++) {
            if (kinds[i] == 'R') {
                unionSet(parent, firstR, i);
            }
        }
        for (int i = 0; i < M; i++) {
            if (edges[i][2] <= 0 || find(parent, edges[i][0]) != find(parent, edges[i][1])) {
                res += edges[i][2];
                unionSet(parent, edges[i][0], edges[i][1]);
            }
        }
        printf("%lld\n", res);
    }
    return 0;
}

