import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static int find(int[] parent, int x) {
        if (parent[x] != x) {
            parent[x] = find(parent, parent[x]);
        }
        return parent[x];
    }

    static int unionSet(int[] parent, int x, int y) {
        int px = find(parent, x);
        int py = find(parent, y);
        if (px != py) {
            parent[px] = py;
            return 1;
        }
        return 0;
    }

    static class Edge implements Comparable<Edge> {
        int u, v, w;

        public Edge(int u, int v, int w) {
            this.u = u;
            this.v = v;
            this.w = w;
        }

        @Override
        public int compareTo(Edge o) {
            return Integer.compare(this.w, o.w);
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            String kinds = scanner.next();
            Edge[] edges = new Edge[M];
            for (int i = 0; i < M; i++) {
                edges[i] = new Edge(scanner.nextInt() - 1, scanner.nextInt() - 1, scanner.nextInt());
            }
            Arrays.sort(edges);
            int[] parent = new int[N];
            for (int i = 0; i < N; i++) {
                parent[i] = i;
            }
            long res = 0;
            int firstR = -1;
            for (int i = 0; i < N; i++) {
                if (kinds.charAt(i) == 'R') {
                    firstR = i;
                    break;
                }
            }
            for (int i = firstR + 1; i < N; i++) {
                if (kinds.charAt(i) == 'R') {
                    unionSet(parent, firstR, i);
                }
            }
            for (int i = 0; i < M; i++) {
                if (edges[i].w <= 0 || find(parent, edges[i].u) != find(parent, edges[i].v)) {
                    res += edges[i].w;
                    unionSet(parent, edges[i].u, edges[i].v);
                }
            }
            System.out.println(res);
        }
    }
}

